+import Yoga from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+
+type Track =
+	| {kind: 'fixed'; size: number}
+	| {kind: 'fr'; value: number; minimum: number}
+	| {kind: 'auto'};
+
+type Placement = {start: number; end: number};
+
+const tokenizeTracks = (template: string | undefined): string[] => {
+	if (!template) {
+		return ['auto'];
+	}
+
+	return template.match(/minmax\\([^)]*\\)|[^\\s]+/g) ?? ['auto'];
+};
+
+const parseTracks = (template: string | undefined): Track[] =>
+	tokenizeTracks(template).map(token => {
+		if (token === 'auto') {
+			return {kind: 'auto'};
+		}
+
+		const minmax = /^minmax\\(\\s*([\\d.]+)\\s*,\\s*([\\d.]+(?:fr)?)\\s*\\)$/.exec(
+			token,
+		);
+		if (minmax) {
+			const minimum = Number(minmax[1]);
+			if (minmax[2].endsWith('fr')) {
+				return {kind: 'fr', value: Number.parseFloat(minmax[2]), minimum};
+			}
+
+			return {kind: 'fixed', size: Number(minmax[2])};
+		}
+
+		if (token.endsWith('fr')) {
+			return {kind: 'fr', value: Number.parseFloat(token), minimum: 0};
+		}
+
+		const size = Number(token);
+		return Number.isFinite(size) ? {kind: 'fixed', size} : {kind: 'auto'};
+	});
+
+const parsePlacement = (value: number | string | undefined): Placement | undefined => {
+	if (typeof value === 'number' && Number.isInteger(value) && value > 0) {
+		return {start: value - 1, end: value};
+	}
+
+	if (typeof value === 'string') {
+		const match = /^\\s*(\\d+)\\s*\\/\\s*(\\d+)\\s*$/.exec(value);
+		if (match) {
+			const start = Number(match[1]) - 1;
+			const end = Number(match[2]) - 1;
+			if (start >= 0 && end > start) {
+				return {start, end};
+			}
+		}
+	}
+
+	return undefined;
+};
+
+const isFree = (
+	occupied: Set<string>,
+	row: number,
+	column: number,
+	rowSpan: number,
+	columnSpan: number,
+): boolean => {
+	for (let y = row; y < row + rowSpan; y++) {
+		for (let x = column; x < column + columnSpan; x++) {
+			if (occupied.has(`${y}:${x}`)) return false;
+		}
+	}
+
+	return true;
+};
+
+const occupy = (
+	occupied: Set<string>,
+	row: number,
+	column: number,
+	rowSpan: number,
+	columnSpan: number,
+): void => {
+	for (let y = row; y < row + rowSpan; y++) {
+		for (let x = column; x < column + columnSpan; x++) occupied.add(`${y}:${x}`);
+	}
+};
+
+const sizeTracks = (
+	tracks: Track[],
+	available: number,
+	gap: number,
+	autoSizes: number[],
+): number[] => {
+	const gaps = gap * Math.max(0, tracks.length - 1);
+	let used = gaps;
+	let frTotal = 0;
+	const sizes = tracks.map((track, index) => {
+		if (track.kind === 'fixed') {
+			used += track.size;
+			return track.size;
+		}
+		if (track.kind === 'auto') {
+			const size = autoSizes[index] ?? 0;
+			used += size;
+			return size;
+		}
+
+		used += track.minimum;
+		frTotal += track.value;
+		return track.minimum;
+	});
+
+	const remaining = Math.max(0, available - used);
+	if (frTotal > 0) {
+		tracks.forEach((track, index) => {
+			if (track.kind === 'fr') sizes[index] += (remaining * track.value) / frTotal;
+		});
+	}
+
+	return sizes;
+};
+
+const offsets = (sizes: number[], gap: number): number[] => {
+	let offset = 0;
+	return sizes.map(size => {
+		const current = offset;
+		offset += size + gap;
+		return current;
+	});
+};
+
+const gridGap = (node: DOMElement, axis: 'column' | 'row'): number =>
+	axis === 'column'
+		? node.style.columnGap ?? node.style.gap ?? 0
