+		const requestedColumn = parsePlacement(child.style.gridColumn);
+		const requestedRow = parsePlacement(child.style.gridRow);
+		const column = requestedColumn ?? {start: cursorColumn, end: cursorColumn + 1};
+		const row = requestedRow ?? {start: cursorRow, end: cursorRow + 1};
+
+		if (!requestedColumn || !requestedRow) {
+			while (!isFree(occupied, row.start, column.start, row.end - row.start, column.end - column.start)) {
+				cursorColumn++;
+				if (cursorColumn >= columns.length) {
+					cursorColumn = 0;
+					cursorRow++;
+				}
+				if (!requestedColumn) {
+					column.start = cursorColumn;
+					column.end = cursorColumn + 1;
+				}
+				if (!requestedRow) {
+					row.start = cursorRow;
+					row.end = cursorRow + 1;
+				}
+			}
+		}
+
