+		if (cursorColumn >= columns.length) {
+			cursorColumn = 0;
+			cursorRow = row.start + 1;
+		}
+	}
+
+	const rowCount = Math.max(rows.length, ...placements.map(item => item.row.end));
+	while (rows.length < rowCount) rows.push({kind: 'auto'});
+	const columnAutoSizes = columns.map(() => 0);
+	const rowAutoSizes = rows.map(() => 0);
+	for (const item of placements) {
+		if (item.column.end - item.column.start === 1 && columns[item.column.start]?.kind === 'auto') {
+			columnAutoSizes[item.column.start] = Math.max(columnAutoSizes[item.column.start], item.node.yogaNode!.getComputedWidth());
+		}
+		if (item.row.end - item.row.start === 1 && rows[item.row.start]?.kind === 'auto') {
+			rowAutoSizes[item.row.start] = Math.max(rowAutoSizes[item.row.start], item.node.yogaNode!.getComputedHeight());
+		}
+	}
+
+	const columnGap = gridGap(node, 'column');
+	const rowGap = gridGap(node, 'row');
+	const columnSizes = sizeTracks(columns, node.yogaNode.getComputedWidth(), columnGap, columnAutoSizes);
+	const rowSizes = sizeTracks(rows, node.yogaNode.getComputedHeight(), rowGap, rowAutoSizes);
+	const columnOffsets = offsets(columnSizes, columnGap);
+	const rowOffsets = offsets(rowSizes, rowGap);
+
+	if (node.style.height === undefined) {
+		node.yogaNode.setHeight(rowSizes.reduce((total, size) => total + size, 0) + rowGap * Math.max(0, rows.length - 1));
+	}
+
+	for (const item of placements) {
+		const width = columnOffsets[item.column.end - 1] + columnSizes[item.column.end - 1] - columnOffsets[item.column.start];
+		const height = rowOffsets[item.row.end - 1] + rowSizes[item.row.end - 1] - rowOffsets[item.row.start];
+		item.node.yogaNode!.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		item.node.yogaNode!.setPosition(Yoga.EDGE_LEFT, columnOffsets[item.column.start]);
+		item.node.yogaNode!.setPosition(Yoga.EDGE_TOP, rowOffsets[item.row.start]);
+		item.node.yogaNode!.setWidth(width);
+		item.node.yogaNode!.setHeight(height);
+	}
+};
+
+const visit = (node: DOMElement): void => {
+	layoutGrid(node);
+	for (const child of node.childNodes) {
+		if ('childNodes' in child) visit(child);
+	}
+};
+
+export const applyGridLayout = (rootNode: DOMElement): void => {
+	// A first Yoga pass supplies intrinsic measurements. Repeating the pass lets nested grids see their assigned size.
+	visit(rootNode);
+};
